import React, { useState } from "react";
import axios from "axios";
import { WiDaySunny, WiHumidity, WiStrongWind } from "react-icons/wi";

const WeatherUpdate = () => {
    const [city, setCity] = useState("");
    const [weather, setWeather] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const fetchWeather = async () => {
        if (!city) {
            setError("Please enter a city name.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const response = await axios.get(`http://localhost:5000/api/weather/getWeather?city=${city}`);
            setWeather(response.data);
        } catch (err) {
            setError("Failed to fetch weather data.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="flex justify-center items-center min-h-screen bg-blue-100">
            <div className="w-full max-w-md p-8 bg-white rounded-2xl shadow-2xl text-center">
                <h2 className="text-3xl font-bold mb-6 text-blue-600">🌤 Weather Update 🌤</h2>
                <input
                    type="text"
                    placeholder="Enter city name"
                    value={city}
                    onChange={(e) => setCity(e.target.value)}
                    className="w-full p-3 border rounded-lg mb-4 text-gray-700 focus:ring-2 focus:ring-blue-400"
                />h
                <button 
                    onClick={fetchWeather} 
                    className="w-full p-3 bg-blue-500 text-white font-semibold rounded-lg hover:bg-blue-600 transition-all"
                >
                    Get Weather
                </button>

                {loading && <p className="text-blue-500 mt-4">Loading...</p>}
                {error && <p className="text-red-500 mt-4">{error}</p>}

                {weather && (
                    <div className="mt-6 p-5 bg-gray-100 rounded-lg shadow-md">
                        <h3 className="text-2xl font-bold text-gray-800">{weather.location}</h3>
                        <p className="text-lg mt-2 flex items-center justify-center">
                            <WiDaySunny className="text-yellow-500 text-3xl mr-2"/> Temperature: {weather.temperature}°C
                        </p>
                        <p className="text-lg mt-2 flex items-center justify-center">
                            <WiHumidity className="text-blue-500 text-3xl mr-2"/> Humidity: {weather.humidity}%
                        </p>
                        <p className="text-lg mt-2 flex items-center justify-center">
                            <WiStrongWind className="text-gray-500 text-3xl mr-2"/> Wind Speed: {weather.wind_speed} m/s
                        </p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default WeatherUpdate;
